import { Get, Controller } from 'routing-controllers';
import { injectable, inject } from 'inversify';
import type { ILogger } from '@hipponot/soa-logger';
import { RestControllerBase, REST_API_BASE_PATH } from '@hipponot/soa-core-api/rest-controller';

const SECTOR = 'user';

@Controller(`/${REST_API_BASE_PATH}/${SECTOR}`)
@injectable()
export class UserRestController extends RestControllerBase {
  readonly sectorName = SECTOR;
  constructor(@inject('ILogger') logger: ILogger) {
    super(logger, SECTOR);
  }

  @Get('/test-route')
  testRoute() {
    this.logger.info('User REST route hit');
    return 'User REST route OK';
  }

  async init() {
    // Async setup if needed
  }
} 